<template>
	<view class="body">
		<scroll-view class="scroll-box" scroll-y @scrolltolower="reachBottom">
		<view class="my-wallet" :style="{
			backgroundImage:'url('+$util.img('/statics/uni/img/wallet_img_bg.png')+')'
		}">
			<view class="back-img" @click="$util.back()"></view>
			<view class="wallet-box" :style="{
			backgroundImage:'url('+$util.img('/statics/uni/img/wallet_img_kapian.png')+')'
		}">
					<view class="top">
						<view class="item">
							<view class="label">
								账户佣金
							</view>
							<view class="value">
									{{parseFloat(balance).toFixed(2)}}
							</view>
						</view>
						<view class="btn" @click="$util.on('/pages/ucenter_sub/draw')">
							提现
						</view>
					</view>
					<view class="bottom">
						<view class="item">
							<view class="label">
								本月佣金
							</view>
							<view class="value">
									{{parseFloat(money_month).toFixed(2)}}
							</view>
						</view>
						<view class="item">
							<view class="label">
								总佣金
							</view>
							<view class="value">
								{{parseFloat(money_month1).toFixed(2)}}
							</view>
						</view>
					</view>
				</view>

				<view class="wallet-list">

					<view class="title">
						<view class="item active">
							提成明细
						</view>
					</view>
					<view class="box-list">
						<view class="item" v-for="(item,index) in list" :key="index">
							<view class="item-title">
								<view class="label">
									{{item.trade_type_text}}
								</view>
								<view class="time">
									{{$util.timeFormat(item.create_time,"yyyy-mm-dd hh:MM:ss")}}
								</view>
							</view>
							<view class="item-money">
								{{item.change_type == 1?'+'+parseFloat(item.money).toFixed(2):'-'+parseFloat(item.money).toFixed(2)}}
							</view>
						</view>
						<u-empty v-if="loaded &&  list.length == 0"></u-empty>
					</view>


				</view>
				<u-loadmore :status="loadStatus" margin-top="20" icon-type="circle" v-if="list.length >0 && loaded" />

			</view>

		</scroll-view>
	</view>
</template>


<script>
	export default {
		data() {
			return {

				sys: this.$util.sys(),
				page: 1,
				limit: 10,
				bg: '',
				kapian: '',
				balance: '0.00',
				money_month: '0.00',
				money_month1: '0.00',

				list: [],
				loaded: false,
				loadStatus: 'loadmore',
				type: 2,
			}
		},


		onLoad() {
			this.loadData();
			this.loadDataList()
		},

		methods: {
			async loadData() {
				// this.loading = true;
				uni.showLoading({
					mask: true,
					title: '加载中...'
				})
				let params = {
					type:this.type
				};
				await this.$u.api.walletConfig(params)
					.then(res => {
						this.bg = res.bg
						this.kapian = res.kapian
						this.balance = res.balance
						this.money_month = res.money_month
						this.money_month1 = res.money_month1

					}).catch(res => {})

				// this.loading = false;
				uni.hideLoading()

			},

			// 页面数据
			async loadDataList() {


				await this.$u.api.walletList({
						type: this.type,
						keyword: this.keyword,
						page: this.page,
						limit: this.limit,
					})
					.then(res => {
						if (res.length == 0) {
							this.loadStatus = 'nomore'
						} else {
							if (this.list.length > 0) {
								this.list = this.list.concat(res.list)

							} else {
								this.list = res.list

							}

							if (res.list.length < this.limit) {
								this.loadStatus = 'nomore'
							} else {
								this.loadStatus = 'loadmore'
							}


							this.page++
						}
					}).catch(res => {})

				this.loaded = true;
				//loaded新字段用于表示数据加载完毕，如果为空可以显示空白页

				// console.log(item	);
			},
			reachBottom() {

				
				setTimeout(() => {
					this.loadDataList();
				}, 200);

			},


		}

	}
</script>

