	.my-wallet .wallet-box .btn {
		width: 160rpx;
		height: 74rpx;
		// background: linear-gradient(180deg, #FFE2C2 0%, #FFCD8D 100%);
		background: #ededed;
		box-shadow: 0 2rpx 6rpx #ffffff, inset 0 4rpx 8rpx rgba(255, 255, 255, .8);
		border-radius: 40rpx;
